// Build context object merging business data with incoming message
const business = $json.data;
const payload = $node['Extract Payload1'].json;
const settings = (() => {
  try { return JSON.parse(business.settings_json || '{}'); } catch { return {}; }
})();
const catalog = (() => {
  try { return JSON.parse(business.catalog_json || '{}'); } catch { return {}; }
})();

return [{
  json: {
    business_id: business.id,
    business_name: business.name,
    branding: settings.branding || {},
    catalog: catalog,
    payment_config: settings.payment || {},
    delivery_config: settings.delivery || {},
    customer_phone: payload.customer_phone,
    message_body: payload.message_body,
    message_type: payload.message_type,
    wa_message_id: payload.wa_message_id,
    timestamp: payload.timestamp
  }
}];

// ─── Resolve Session ID ────────────────────────────────────────────────
// IMPORTANT: This node is reached from TWO possible paths:
//   TRUE branch  → came from 'Resolve Active Session' (session existed)
//   FALSE branch → came from 'Create Session' (new session created)
//
// We CANNOT reference both nodes by name — n8n throws if a node didn't run.
// Instead, use $input.item.json which is always the direct input from whichever
// branch was taken in this execution.
const input = $input.item.json;

// Extract session_id — works for both active session response and create response
const session_id = input?.data?.session_id   // active session shape
                || input?.data?.id;           // created session shape

const fsm_state   = input?.data?.fsm_state || 'START';
const carry_unit  = input?.data?.carry_unit || {};

if (!session_id) {
  throw new Error(
    'Could not resolve session_id from input. ' +
    'Input received: ' + JSON.stringify(input)
  );
}

// Carry forward the full execution context from Build Execution Context
// (that node always runs before the session branch, so it's safe to reference)
const ctx = (() => {
  try { return $node['Build Execution Context1'].json; } catch(e) {}
  try { return $node['Build Execution Context'].json; } catch(e) {}
  throw new Error("Could not find 'Build Execution Context' or 'Build Execution Context1' node.");
})();

return [{
  json: {
    session_id,
    fsm_state,
    carry_unit,
    business_id:    ctx.business_id,
    business_name:  ctx.business_name,
    branding:       ctx.branding,
    catalog:        ctx.catalog,
    payment_config: ctx.payment_config,
    delivery_config:ctx.delivery_config,
    customer_phone: ctx.customer_phone,
    message_body:   ctx.message_body,
    message_type:   ctx.message_type
  }
}];

const result = $json.data || {};
const ctx = $node["Resolve Session ID1"].json || {};

// Standardized UI object
const ui = result.ui || {
  text: (result.messages_sent || []).map(m => typeof m === "string" ? m : (m.content || m.text || m.message || "")).join("\n\n").trim(),
  actions: (result.allowed_actions || []).map(a => ({
    label: a.title || a.label || "",
    action: a.id || a.action || ""
  })),
  metadata: {}
};

// Side effects
const side_effects = result.side_effects || [];

// Carry unit
const carry_unit = result.carry_unit || ctx.carry_unit || {};

// FSM state
let fsm_state = result.fsm_state || ctx.fsm_state || "UNKNOWN";

// Fallback: derive latest FSM state from execution trace
if (
  !result.fsm_state &&
  result.workflow &&
  result.workflow.execution_trace &&
  result.workflow.execution_trace.length > 0
) {
  try {
    const lastTrace = JSON.parse(
      result.workflow.execution_trace[
        result.workflow.execution_trace.length - 1
      ]
    );

    fsm_state =
      lastTrace.fsm_state_after ||
      lastTrace.fsm_state_before ||
      fsm_state;
  } catch (err) {
    // ignore parse errors
  }
}

// Build WhatsApp reply text (with fallback to ui.text)
const reply_text = ui.text || "";

// Return parsed payload
return [
  {
    json: {
      customer_phone: ctx.customer_phone,
      business_name: ctx.business_name,
      business_id: ctx.business_id,
      branding_prefix: ctx.branding_prefix || "",

      ui,
      reply_text,
      fsm_state,
      carry_unit,
      side_effects,
    },
  },
];

const ctx = $node["Execute Side Effects1"].json;
const ui = ctx.ui || {};
const reply_text = ctx.reply_text || ui.text || '';
const actions = ui.actions || ctx.allowed_actions || [];

let whatsapp_payload;

if (actions.length > 0 && actions.length <= 3) {
  // Send interactive message with action buttons (max 3 for WhatsApp)
  whatsapp_payload = {
    messaging_product: 'whatsapp',
    to: ctx.customer_phone,
    type: 'interactive',
    interactive: {
      type: 'button',
      body: { text: reply_text || 'What would you like to do?' },
      action: {
        buttons: actions.map(action => ({
          type: 'reply',
          reply: { id: action.action || action.id, title: action.label || action.title }
        }))
      }
    }
  };
} else {
  // Send plain text message
  whatsapp_payload = {
    messaging_product: 'whatsapp',
    to: ctx.customer_phone,
    type: 'text',
    text: { body: reply_text }
  };
}

return [{
  json: {
    customer_phone: ctx.customer_phone,
    business_name: ctx.business_name,
    fsm_state: ctx.fsm_state,
    whatsapp_payload: JSON.stringify(whatsapp_payload)
  }
}];

// Orchestration event logger.
// Logs webhook events, actions executed, and delivery status.
// DOES NOT duplicate FlowCore's replay semantics — FlowCore owns runtime journals.
const result = $json;
console.log(JSON.stringify({
  event: 'ORCHESTRATION_COMPLETE',
  timestamp: new Date().toISOString(),
  business: $node['Build WhatsApp Message1'].json.business_name,
  customer: $node['Build WhatsApp Message1'].json.customer_phone,
  fsm_state: $node['Build WhatsApp Message1'].json.fsm_state,
  send_status: result.messages?.[0]?.message_status || result.error?.message || 'SENT'
}));
return [{ json: { logged: true } }];

// ─────────────────────────────────────────────────────────────
// STEP 1: Extract payload from Meta Cloud API webhook structure
// Handles both text messages and interactive button replies.
// ─────────────────────────────────────────────────────────────
const body = $json.body;
const entry = body?.entry?.[0];
const change = entry?.changes?.[0]?.value;
const metadata = change?.metadata;
const message = change?.messages?.[0];

// Drop non-message events (read receipts, status updates, etc.)
if (!message) {
  return [];
}

let messageText = '';
let messageType = message.type;

if (message.type === 'text') {
  messageText = message.text?.body || '';
} else if (message.type === 'interactive') {
  // Interactive button reply — button ID maps to operational action commands
  const reply = message.interactive?.button_reply || message.interactive?.list_reply;
  messageText = reply?.id || reply?.title || '';
  messageType = 'button_action';
} else {
  // Unsupported message type — pass through raw for FlowCore to handle
  messageText = `[${message.type}]`;
}

return [{
  json: {
    meta_phone_number_id: metadata?.phone_number_id,
    display_phone_number: metadata?.display_phone_number,
    customer_phone: message.from,
    message_body: messageText,
    message_type: messageType,
    wa_message_id: message.id,
    timestamp: message.timestamp
  }
}];

const ctx = $json;
const side_effects = ctx.side_effects || [];

let reply_text = ctx.reply_text || "";

for (const effect of side_effects) {
  const type = effect.type || effect.side_effect;
  const payload = effect.payload || {};

  console.log(`[SIDE EFFECT] Executing type=${type} with payload=${JSON.stringify(payload)}`);

  switch (type) {
    case "CREATE_PAYMENT_LINK":
    case "external_gateway_handshake": {
      const amount = payload.amount || ctx.carry_unit?.order?.total || 0;
      const currency = ctx.payment_config?.currency || 'USD';
      const order_id = ctx.carry_unit?.order?.order_id || 'ORD-UNKNOWN';
      const tx_id = payload.transaction_id || `tx_${Math.random().toString(36).substring(2, 9)}`;
      const payment_url = payload.payment_url || `https://pay.flowcore.io/link/${tx_id}`;

      console.log(`[PAYMENT] CREATE_PAYMENT_LINK Amount=${amount} ${currency} Tx=${tx_id}`);

      reply_text = `${ctx.branding_prefix || ""}Payment Link for your order:\n${payment_url}\n\nAmount: ${currency} ${amount}\n\n${reply_text}`;
      break;
    }
    case "CREATE_DELIVERY":
    case "dispatch_delivery_courier": {
      const address = payload.address || ctx.carry_unit?.customer?.address || 'Address on file';
      const tracking_id = payload.delivery_id || `TRK-${Date.now().toString(36).toUpperCase()}`;

      console.log(`[DELIVERY] CREATE_DELIVERY Address=${address} Tracking=${tracking_id}`);

      reply_text = `${ctx.branding_prefix || ""}Your order has been dispatched!\n\nTracking ID: ${tracking_id}\nDelivery address: ${address}\n\n${reply_text}`;
      break;
    }
    case "SEND_NOTIFICATION": {
      const message = payload.message || "Notification Alert";
      console.log(`[NOTIFICATION] SEND_NOTIFICATION message=${message}`);
      break;
    }
    case "SYNC_CRM": {
      console.log(`[CRM] SYNC_CRM syncing data`);
      break;
    }
    default:
      console.warn(`[SIDE EFFECT] Unknown effect type: ${type}. Skipping to prevent workflow crash.`);
      break;
  }
}

return [{
  json: {
    ...ctx,
    reply_text: reply_text.trim()
  }
}];
